export function taskExamplesFor(taskId: number): ResolvedTaskExample[] {
  const list = taskCaseExamples[taskId] ?? [];
  return list
    .map((e) => ({ ...e, company: caseStudyBySlug(e.slug) }))
    .filter((e): e is ResolvedTaskExample => Boolean(e.company));
}
